// merge queue row + sender info into a single job object
// handles all content types: youtube, web, x-post, github, pdf, braindump, voice-note, local-video/audio/book, translate-book

const jobItems = $('Pick Job').all();
const senderItems = $('Get Sender Info').all();

const job = jobItems[0]?.json || {};
const sender = senderItems[0]?.json || {};

// flags come as JSONB, might be string or object
let flags = {};
if (job.flags) {
  if (typeof job.flags === 'string') {
    try { flags = JSON.parse(job.flags); } catch(e) {}
  } else {
    flags = job.flags;
  }
}

// content type was set by Ingestion, trust it
let contentType = job.content_type || 'web';

// normalize content key for cache lookups (must match Ingestion logic)
const url = job.url || '';
let contentKey = '';

if (contentType === 'youtube' || url.match(/youtube\.com|youtu\.be/)) {
  contentType = 'youtube';
  const vidMatch = url.match(/(?:v=|youtu\.be\/)([a-zA-Z0-9_-]{11})/);
  contentKey = vidMatch ? `yt:${vidMatch[1]}` : `web:${url.replace(/^https?:\/\//, '').replace(/[?#].*$/, '')}`;
} else if (contentType === 'braindump' || contentType === 'voice-note') {
  // No URL for these types. content key stays empty
  contentKey = '';
} else if (contentType === 'local-video' || contentType === 'local-audio' || contentType === 'local-book' || contentType === 'translate-book') {
  // Local files from NextCloud. content key from queue metadata
  try {
    const meta = JSON.parse(job.message_text || '{}');
    contentKey = meta.contentKey || `file:${contentType}_${job.id}`;
  } catch(e) {
    contentKey = `file:${contentType}_${job.id}`;
  }
} else if (url) {
  // URL-based types: normalize to web: key
  const cleanUrl = url.replace(/^https?:\/\//, '').replace(/\/$/,'');
  // Remove tracking params for cache key
  try {
    const parsed = new URL(url);
    const trackingParams = ['utm_source','utm_medium','utm_campaign','utm_term','utm_content','fbclid','gclid','ref','ref_src','ref_url','mc_cid','mc_eid','s','si'];
    for (const p of trackingParams) parsed.searchParams.delete(p);
    const hostPath = parsed.hostname.toLowerCase() + parsed.pathname.replace(/\/$/,'');
    const query = parsed.searchParams.toString() ? '?' + parsed.searchParams.toString() : '';
    contentKey = `web:${hostPath}${query}`;
  } catch(e) {
    contentKey = `web:${cleanUrl}`;
  }
}

// Extract test parameters from message_text (for translate-book test runs)
let testParams = null;
if (contentType === 'translate-book' && job.message_text) {
  try {
    const meta = JSON.parse(job.message_text);
    if (meta.testParams) testParams = meta.testParams;
  } catch(e) {}
}

return [{ json: {
  _jobId: job.id,
  _url: url,
  _contentType: contentType,
  _flags: flags,
  _priority: job.priority || 'normal',
  _messageText: job.message_text || '',
  _sourceChannel: job.source_channel || 'signal',
  _contentKey: contentKey,
  _createdAt: job.created_at,
  // Sender fields
  _userId: sender.id || job.sender || 1,
  _senderName: sender.name || 'Unknown',
  _userRole: sender.role || 'user',
  _senderUuid: sender.signal_uuid || '',
  _senderEmail: sender.email || '',
  // Test parameters (null if not a test run)
  _testParams: testParams
} }];

// send 'Processing [title]...' to admin users
// runs AFTER yt-dlp Download so we have the video title

const item = $input.first().json;
const prepareData = $('Prepare Job').first().json;
const isAdmin = prepareData._userRole === 'admin';

// Only send progress to admin users (don't disturb users at night)
if (isAdmin) {
  // Extract title from yt-dlp output
  let title = 'YouTube video';
  try {
    if (item.title) {
      title = item.title;
    } else if (item.info && item.info.title) {
      title = item.info.title;
    } else if (item._title) {
      title = item._title;
    }
    if (title.length > 80) title = title.substring(0, 77) + '...';
  } catch(e) {}

  // Unicode Bold converter
  function toBold(text) {
    const boldMap = {};
    for (let i = 0; i < 26; i++) {
      boldMap[String.fromCharCode(65 + i)] = String.fromCodePoint(0x1D5D4 + i);
    }
    for (let i = 0; i < 26; i++) {
      boldMap[String.fromCharCode(97 + i)] = String.fromCodePoint(0x1D5EE + i);
    }
    for (let i = 0; i < 10; i++) {
      boldMap[String.fromCharCode(48 + i)] = String.fromCodePoint(0x1D7EC + i);
    }
    return text.split('').map(c => boldMap[c] || c).join('');
  }

  const msg = `\u23f3 Processing ${toBold(title)}`;

  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'http://YOUR_HOST_IP:8082/v2/send',
      body: {
        message: msg,
        number: 'YOUR_PHONE_NUMBER',
        recipients: [prepareData._senderUuid]
      },
      headers: { 'Content-Type': 'application/json' },
      timeout: 10000
    });
  } catch (e) {}
}

return [{ json: item }];

// parse YouTube URL into video ID + slug

const item = $input.first().json;
const url = item._url || '';

// covers: watch?v=, youtu.be/, embed/, shorts/
let videoId = '';
const patterns = [
  /(?:youtube\.com\/watch\?v=)([a-zA-Z0-9_-]{11})/,
  /(?:youtu\.be\/)([a-zA-Z0-9_-]{11})/,
  /(?:youtube\.com\/embed\/)([a-zA-Z0-9_-]{11})/,
  /(?:youtube\.com\/shorts\/)([a-zA-Z0-9_-]{11})/,
];

for (const p of patterns) {
  const match = url.match(p);
  if (match) { videoId = match[1]; break; }
}

if (!videoId) {
  throw new Error('Could not extract YouTube video ID from URL: ' + url);
}

return [{ json: { ...item, _videoId: videoId, _contentType: 'youtube', _pipeline: 'youtube' } }];

// download YouTube audio via yt-dlp
// grabs mp3 + metadata, hands file path to Whisper
// mp3 not WAV because large WAVs can OOM the container
// async exec so the event loop stays alive for heartbeats
// important: NOT execFileSync. long downloads (>30s) will
// kill the heartbeat. 2h30 video takes about 2min to download.
// Temp files are cleaned up by Whisper Transcribe after sending.

const { execFile } = require('child_process');
const fs = require('fs');
const path = require('path');

const item = $input.first().json;
const videoId = item._videoId;
const url = `https://www.youtube.com/watch?v=${videoId}`;

const tmpDir = '/tmp';
const stamp = String(Date.now()) + '_' + Math.random().toString(36).slice(2, 8);
const outputTemplate = path.join(tmpDir, `ytdlp_${stamp}.%(ext)s`);
const outputPath = path.join(tmpDir, `ytdlp_${stamp}.mp3`);
const metaPath = path.join(tmpDir, `ytdlp_${stamp}.info.json`);

// async. event loop stays alive, heartbeats keep flowing
await new Promise((resolve, reject) => {
  execFile('/usr/local/bin/yt-dlp', [
    '--no-playlist',
    '-x', '--audio-format', 'mp3',
    '--audio-quality', '5',
    '--write-info-json',
    '--ffmpeg-location', '/usr/bin/ffmpeg',
    '-o', outputTemplate,
    url
  ], { timeout: 600000, maxBuffer: 10 * 1024 * 1024 }, (error, stdout, stderr) => {
    if (error) {
      const stderrStr = stderr ? stderr.toString().substring(0, 500) : '';
      const msg = error.message ? error.message.substring(0, 200) : 'unknown';
      reject(new Error(`yt-dlp failed: ${msg}. ${stderrStr}`));
    } else {
      resolve();
    }
  });
});

// Read metadata for title/duration/channel/upload_date
let title = videoId;
let duration = 0;
let channel = '';
let uploadDate = '';
try {
  const meta = JSON.parse(fs.readFileSync(metaPath, 'utf-8'));
  title = meta.title || videoId;
  duration = meta.duration || 0;
  channel = meta.channel || meta.uploader || '';
  // yt-dlp upload_date is YYYYMMDD format. convert to YYYY-MM-DD
  if (meta.upload_date) {
    const d = meta.upload_date;
    uploadDate = d.length === 8 ? `${d.slice(0,4)}-${d.slice(4,6)}-${d.slice(6,8)}` : d;
  }
} catch(e) { /* metadata optional */ }

// Check audio file exists
if (!fs.existsSync(outputPath)) {
  throw new Error(`Audio file not found at ${outputPath}. Check yt-dlp output.`);
}

const audioSize = fs.statSync(outputPath).size;

// Generate slug from title
const slug = title.toLowerCase()
  .replace(/[^a-z0-9\s-]/g, '')
  .replace(/\s+/g, '-')
  .substring(0, 60);

const today = new Date().toISOString().split('T')[0];

// NOTE: Do NOT clean up temp files here. Whisper Transcribe reads _audioPath
// NOTE: Do NOT load audio into memory. pass file path to avoid OOM
return [{
  json: {
    ...item,
    _title: title,
    _slug: slug,
    _duration: duration,
    _filename: `${today}_${slug}.md`,
    _vaultPath: `30-SIGNALS/32-YouTube/${today}_${slug}.md`,
    _transcriptPath: `30-SIGNALS/32-YouTube/.transcripts/${today}_${slug}.txt`,
    _audioPath: outputPath,
    _audioBytes: audioSize,
    _tmpStamp: stamp,
    _channel: channel,
    _uploadDate: uploadDate
  }
}];

const { execFile } = require('child_process');
const fs = require('fs');

const item = $input.first().json;
const audioPath = item._audioPath;
const tmpStamp = item._tmpStamp;

if (!audioPath) throw new Error('No _audioPath received from yt-dlp Download');
if (!fs.existsSync(audioPath)) throw new Error(`Audio file not found: ${audioPath}`);

const responsePath = `/tmp/whisper_resp_${tmpStamp}.json`;

// Child Node.js script: streams audio to whisper, writes response to file
const uploaderScript = `
const http = require('http');
const fs = require('fs');

const audioPath = process.argv[1];
const host = process.argv[2];
const port = parseInt(process.argv[3]);
const urlPath = process.argv[4];
const outPath = process.argv[5];

const boundary = 'n8nWhisper' + Date.now().toString(36);
const fileName = audioPath.endsWith('.wav') ? 'audio.wav' : 'audio.mp3';
const mimeType = audioPath.endsWith('.wav') ? 'audio/wav' : 'audio/mpeg';
const fileSize = fs.statSync(audioPath).size;

const prefix = Buffer.from(
  '--' + boundary + '\\r\\n' +
  'Content-Disposition: form-data; name="file"; filename="' + fileName + '"\\r\\n' +
  'Content-Type: ' + mimeType + '\\r\\n\\r\\n'
);
const suffix = Buffer.from(
  '\\r\\n--' + boundary + '\\r\\n' +
  'Content-Disposition: form-data; name="response_format"\\r\\n\\r\\n' +
  'verbose_json\\r\\n' +
  '--' + boundary + '\\r\\n' +
  'Content-Disposition: form-data; name="language"\\r\\n\\r\\n' +
  'auto\\r\\n' +
  '--' + boundary + '--\\r\\n'
);

const req = http.request({
  hostname: host, port: port, path: urlPath, method: 'POST',
  headers: {
    'Content-Type': 'multipart/form-data; boundary=' + boundary,
    'Content-Length': prefix.length + fileSize + suffix.length
  },
  timeout: 900000
}, (res) => {
  const chunks = [];
  res.on('data', (chunk) => { chunks.push(chunk); });
  res.on('end', () => {
    fs.writeFileSync(outPath, Buffer.concat(chunks));
    process.exit(res.statusCode >= 400 ? 1 : 0);
  });
});
req.on('error', (e) => {
  fs.writeFileSync(outPath, JSON.stringify({error: e.message}));
  process.exit(1);
});
req.on('timeout', () => { req.destroy(new Error('timeout')); });

req.write(prefix);
const stream = fs.createReadStream(audioPath, { highWaterMark: 64 * 1024 });
stream.on('data', (chunk) => { req.write(chunk); });
stream.on('end', () => { req.write(suffix); req.end(); });
stream.on('error', (e) => {
  fs.writeFileSync(outPath, JSON.stringify({error: e.message}));
  process.exit(1);
});
`;

let nodePath = '/usr/local/bin/node';
if (!fs.existsSync(nodePath)) nodePath = '/usr/bin/node';

// ASYNC execFile. does NOT block the event loop, so task runner heartbeat stays alive
// Timeout: 920s (15min+) for very long videos (2h30+)
await new Promise((resolve, reject) => {
  execFile(nodePath, [
    '-e', uploaderScript,
    audioPath, 'whisper-signal', '8084', '/v1/audio/transcriptions', responsePath
  ], { timeout: 920000, maxBuffer: 1024 * 1024 }, (error, stdout, stderr) => {
    if (error && !fs.existsSync(responsePath)) {
      reject(new Error(`Whisper failed: ${error.message.substring(0, 200)}`));
    } else {
      resolve();
    }
  });
});

// Read response from file
if (!fs.existsSync(responsePath)) {
  throw new Error('Whisper response file not created');
}
const responseText = fs.readFileSync(responsePath, 'utf-8');
try { fs.unlinkSync(responsePath); } catch(e) {}

let response;
try {
  response = JSON.parse(responseText);
} catch (e) {
  throw new Error('Invalid JSON (' + responseText.length + ' chars): ' + responseText.substring(0, 200));
}
if (response.error) throw new Error('Whisper error: ' + response.error);

// Clean up yt-dlp temp files
try {
  if (tmpStamp) {
    fs.readdirSync('/tmp').filter(f => f.includes(tmpStamp)).forEach(f => {
      try { fs.unlinkSync('/tmp/' + f); } catch(e) {}
    });
  }
} catch(e) {}

const { _audioPath: _ap, _tmpStamp: _ts, ...rest } = item;
return [{ json: { ...rest, ...response } }];

const item = $input.first().json;

// Whisper response fields are merged into item by Whisper Transcribe Code node
// Contains: text, segments[], language, duration + all yt-dlp passthrough fields
const videoId = item._videoId || '';
const segments = item.segments || [];
const fullText = item.text || '';

// Query SponsorBlock API inline for sponsor segment timestamps
let sponsorSegments = [];
if (videoId) {
  try {
    const sbResponse = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://sponsor.ajay.app/api/skipSegments?videoID=${videoId}&categories=["sponsor","selfpromo","interaction"]`,
      timeout: 10000
    });
    if (Array.isArray(sbResponse)) {
      sponsorSegments = sbResponse;
    }
  } catch (e) {
    // 404 = no sponsor segments found (normal for most videos)
    // Any other error = just proceed without filtering
  }
}

// Filter out sponsor segments from transcript
let filteredSegments = segments;
let sponsorRemoved = 0;

if (sponsorSegments.length > 0 && segments.length > 0) {
  filteredSegments = segments.filter(seg => {
    const segStart = seg.start || 0;
    const segEnd = seg.end || segStart;

    const isSponsored = sponsorSegments.some(sponsor => {
      const sStart = sponsor.segment?.[0] || 0;
      const sEnd = sponsor.segment?.[1] || 0;
      return segStart < sEnd && segEnd > sStart;
    });

    if (isSponsored) sponsorRemoved++;
    return !isSponsored;
  });
}

const filteredText = filteredSegments.map(s => s.text || '').join(' ').trim();

// Clean up raw whisper fields from output, keep pipeline fields
const { segments: _segs, words: _w, text: _t, task: _task,
        language_probabilities: _lp, ...rest } = item;

return [{ json: {
  ...rest,
  _transcript: filteredText || fullText,
  _rawTranscript: fullText,
  _sponsorSegmentsRemoved: sponsorRemoved,
  _totalSegments: segments.length,
  _detectedLanguage: item.language || item.detected_language || 'unknown'
}}];

// extract summary + metadata from Qwen response
// pulls creator, published, language, tags from Qwen's YAML-like header

const item = $input.first().json;
const fullResponse = item._llmResponse?.choices?.[0]?.message?.content || '';

// Parse METADATA block from Qwen output
// Format: "METADATA:\nkey: value\n...\n---\n<summary>"
let creator = item._channel || '';
let published = item._uploadDate || '';
let language = '';
let tags = [];
let summary = fullResponse;

const metaMatch = fullResponse.match(/^METADATA:\s*\n([\s\S]*?)\n---/);
if (metaMatch) {
  const metaBlock = metaMatch[1];
  // Extract each field
  const creatorMatch = metaBlock.match(/^creator:\s*(.+)$/m);
  const publishedMatch = metaBlock.match(/^published:\s*(.+)$/m);
  const languageMatch = metaBlock.match(/^language:\s*(.+)$/m);
  const tagsMatch = metaBlock.match(/^tags:\s*(.+)$/m);

  if (creatorMatch) creator = creatorMatch[1].trim();
  if (publishedMatch) published = publishedMatch[1].trim();
  if (languageMatch) language = languageMatch[1].trim();
  if (tagsMatch) {
    tags = tagsMatch[1].split(',').map(t => t.trim()).filter(t => t.length > 0);
  }

  // Summary is everything after the --- separator
  summary = fullResponse.substring(metaMatch.index + metaMatch[0].length).trim();
}

// Prefer yt-dlp metadata over Qwen extraction for creator/published
if (item._channel) creator = item._channel;
if (item._uploadDate) published = item._uploadDate;

// Remove _llmResponse (large, no longer needed)
const { _llmResponse, ...rest } = item;

return [{ json: {
  ...rest,
  _summary: summary,
  _contentType: 'youtube',
  _pipeline: 'youtube',
  _creator: creator,
  _published: published,
  _language: language,
  _tags: tags
} }];

// write raw transcript to vault, pass through all data

const item = $input.first().json;

try {
  const content = '# Transcript: ' + (item._title || 'Unknown') +
    '\nVideo: ' + (item._url || '') +
    '\nLanguage: ' + (item._detectedLanguage || 'unknown') +
    '\nSponsor segments removed: ' + (item._sponsorSegmentsRemoved || 0) +
    '\n\n' + (item._rawTranscript || 'No transcript.');

  await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://localhost:5678/webhook/vault',
    body: { action: 'write', path: item._transcriptPath, content },
    headers: { 'Content-Type': 'application/json' },
    timeout: 30000
  });
} catch (e) {
  // Don't fail pipeline if transcript save fails
}

return [{ json: item }];

// send progress notification to admin for web-like content types
// content-type-aware icons and messages

const item = $input.first().json;
const prepareData = $('Prepare Job').first().json;
const _userRole = item._userRole || prepareData._userRole || 'user';
const _senderUuid = item._senderUuid || prepareData._senderUuid || '';

// Skip progress messages for non-admin users (don't disturb at night)
if (_userRole !== 'admin') {
  return [{ json: item }];
}

// Extract title from Crawl4AI response
let title = '';
if (item.results && item.results[0]) {
  const md = item.results[0].markdown;
  const rawMd = typeof md === 'string' ? md : (md?.raw_markdown || '');
  const titleMatch = rawMd.match(/^#\s+(.+)/m);
  if (titleMatch) title = titleMatch[1].trim().substring(0, 80);
}
if (!title) title = item._url || 'content';

// Content-type-aware icon
const ct = item._contentType || prepareData._contentType || 'web';
const icons = {
  'web': '\u{1F310}', 'x-post': '\u{1D54F}', 'github': '\u{1F4BB}',
  'paper': '\u{1F4C4}', 'youtube': '\u{1F3AC}'
};
const icon = icons[ct] || '\u{1F310}';

// Unicode bold for title
function toBold(text) {
  const map = {};
  for (let i = 0; i < 26; i++) { map[String.fromCharCode(65+i)] = String.fromCodePoint(0x1D5D4+i); }
  for (let i = 0; i < 26; i++) { map[String.fromCharCode(97+i)] = String.fromCodePoint(0x1D5EE+i); }
  for (let i = 0; i < 10; i++) { map[String.fromCharCode(48+i)] = String.fromCodePoint(0x1D7EC+i); }
  return text.split('').map(c => map[c] || c).join('');
}

const msg = `\u23F3 Processing ${icon} ${toBold(title)}`;

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://YOUR_HOST_IP:8082/v2/send',
    body: { message: msg, number: 'YOUR_PHONE_NUMBER', recipients: [_senderUuid || 'YOUR_UUID'] },
    headers: { 'Content-Type': 'application/json' },
    timeout: 5000
  });
} catch(e) { /* ignore send errors */ }

return [{ json: item }];

// scrape web content. X/Twitter goes through FxTwitter (X blocks direct scraping)
// X.com has a cookie wall — FxTwitter gives us clean JSON with article body + thread chains
// flow: detect content type -> FxTwitter V2 /thread/ (handles singles + threads)
// fallback: if V2 returns thin content (<200 chars), try V1 for article body

const item = $input.first().json;
const url = item._url || '';
const ct = item._contentType || '';

function safeText(val) {
  if (!val) return '';
  if (typeof val === 'string') return val;
  if (typeof val === 'object') return val.text || val.raw_text || JSON.stringify(val);
  return String(val);
}

// formatArticleBlocks. convert FxTwitter article blocks to markdown.
function formatArticleBlocks(article) {
  if (!article?.content?.blocks) return '';
  let md = '';
  if (article.title) md += `**Article: ${article.title}**\n\n`;
  for (const block of article.content.blocks) {
    const text = safeText(block.text || block);
    if (!text) continue;
    // Skip empty blocks or raw JSON artifacts from FxTwitter
    if (text.startsWith('{') && text.includes('"data"')) continue;
    if (block.type && block.type.startsWith('header')) {
      md += `### ${text}\n\n`;
    } else {
      md += text + '\n\n';
    }
  }
  return md;
}

// ---- X/TWITTER: Use FxTwitter API ----
if (ct === 'x-post' || /(?:x\.com|twitter\.com)\/\w+\/status\/\d+/.test(url)) {
  const match = url.match(/(?:x\.com|twitter\.com)\/([^\/\?]+)\/status\/(\d+)/);
  if (!match) {
    throw new Error(`Could not extract tweet ID from URL: ${url}`);
  }
  const [, username, tweetId] = match;

  // Step 1: Fetch via V2 thread endpoint (handles single tweets AND threads)
  let thread = [];
  let v2Status = {};
  try {
    const v2 = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://api.fxtwitter.com/2/thread/${tweetId}`,
      headers: { 'User-Agent': 'STMNA-Signal/1.0' },
      timeout: 30000
    });
    thread = v2.thread || [];
    v2Status = v2.status || {};
  } catch (e) {
    // V2 failed. will try V1 below
  }

  // Step 2: Build markdown from thread
  let markdown = '';
  let authorName = '';
  let authorHandle = username;

  if (thread.length > 1) {
    // ---- THREAD: concatenate all tweets ----
    const first = thread[0];
    authorHandle = first?.author?.screen_name || username;
    authorName = first?.author?.name || '';
    const dateStr = first?.created_at || v2Status.created_at || '';
    markdown = `# Thread by @${authorHandle} (${authorName})\n`;
    if (dateStr) markdown += `**Published:** ${dateStr}\n`;
    markdown += '\n';

    for (let i = 0; i < thread.length; i++) {
      const t = thread[i];
      const tweetText = safeText(t.text) || safeText(t.raw_text);
      markdown += `**[${i + 1}/${thread.length}]** `;
      if (tweetText) markdown += tweetText + '\n\n';

      // Include article body if present in any tweet
      markdown += formatArticleBlocks(t.article);
    }

    // Thread stats from the entry tweet
    const s = v2Status;
    if (s.likes) {
      markdown += `---\n*${thread.length} tweets | ${s.likes || 0} likes | ${s.reposts || s.retweets || 0} reposts | ${s.replies || 0} replies*\n`;
    }

  } else {
    // ---- SINGLE TWEET or V2 returned 1 item ----
    const tweet = thread[0] || v2Status || {};
    const author = tweet.author || {};
    authorHandle = author.screen_name || username;
    authorName = author.name || '';
    const dateStr = tweet.created_at || v2Status.created_at || '';
    const tweetText = safeText(tweet.text) || safeText(tweet.raw_text);

    markdown = `# Post by @${authorHandle} (${authorName})\n`;
    if (dateStr) markdown += `**Published:** ${dateStr}\n`;
    markdown += '\n';

    // Only add tweet text if it's not just a t.co link pointing to the article
    if (tweetText && !tweetText.match(/^https?:\/\/t\.co\/\w+$/)) {
