      markdown += formatArticleBlocks(tweet.article);

      if (tweet.likes) {
        markdown += `---\n*${tweet.likes || 0} likes | ${tweet.retweets || 0} retweets | ${tweet.replies || 0} replies | ${tweet.views || 0} views*\n`;
      }
    } catch (e) {
      // V1 also failed. use whatever we have from V2
    }
  }

  // Return in Crawl4AI-compatible format (downstream reads results[0].markdown)
  return [{ json: { ...item, results: [{ markdown: markdown }] } }];
