// cleanTitle. Strip Calibre/Pandoc HTML artifacts + redundant CHAPTER N prefix
// v2: strip {...} first, then brackets. handles nested Calibre CSS
function cleanTitle(raw) {
  let t = raw;
  // Strip ALL {...} attributes first
  t = t.replace(/\{[^}]*\}/g, '');
  // Strip anchor links [text](#ref)
  t = t.replace(/\[([^\]]*)\]\(#[^)]*\)/g, '$1');
  // Strip bare brackets
  t = t.replace(/\[/g, '').replace(/\]/g, '');
  t = t.replace(/\s+/g, ' ').trim();
  t = t.replace(/^[#\s]+/, '').replace(/\s+$/, '');
  // Strip "CHAPTER N" / "CHAPTER N:" / "Chapter N -" prefix
  t = t.replace(/^CHAPTER\s+\d+[\s:\u2014\u2013-]*/i, '').trim();
  return t || 'Untitled';
}

// cleanAllCss v2. Strip ALL CSS/anchor/HTML artifacts from a line
// Key fix: strip {...} FIRST before bracket patterns (handles deep nesting)
function cleanAllCss(line) {
  let t = line.trim();
  // Remove pandoc raw HTML blocks like `<big>`{=html}
  t = t.replace(/`<[^>]+>`\{=html\}/g, '');
  // v2: Strip ALL {...} attributes FIRST. handles nested Calibre CSS
  // e.g. [[[text]{.bold}]{.calibre3}] -> [[[text]]]
  t = t.replace(/\{[^}]*\}/g, '');
  // Strip anchor links [text](#ref)
  t = t.replace(/\[([^\]]*)\]\(#[^)]*\)/g, '$1');
  // Strip ALL remaining brackets (nested or otherwise)
  t = t.replace(/\[/g, '').replace(/\]/g, '');
  // Strip remaining bare refs (#anchor)
  t = t.replace(/\(#[^)]*\)/g, '');
  // Strip footnote superscripts ^N^
  t = t.replace(/\^\d+\^/g, '');
  // Strip trailing backslash (continuation marker)
  t = t.replace(/\\$/g, '');
  t = t.replace(/\s+/g, ' ').trim();
  return t;
}

