    text: currentChapter.text.trim()
  });
}

// Try H2 if H1 didn't work
if (rawChapters.length <= 1) {
  rawChapters = [];
  currentChapter = { title: '', text: '' };
  for (const line of lines) {
    const h2Match = line.match(/^## (.+)$/);
    if (h2Match) {
      if (currentChapter.text.trim().length > 500) {
        rawChapters.push({
          title: cleanTitle(currentChapter.title),
          text: currentChapter.text.trim()
        });
      }
      currentChapter = { title: h2Match[1].trim(), text: '' };
    } else {
      currentChapter.text += line + '\n';
    }
  }
  if (currentChapter.text.trim().length > 500) {
    rawChapters.push({
      title: cleanTitle(currentChapter.title),
      text: currentChapter.text.trim()
    });
  }
}

// Fallback 3: Calibre CSS headings (no H1/H2 in pandoc output)
// v2: Join continuation lines, detect number words, merge pairs
if (rawChapters.length <= 1) {
  rawChapters = [];
  currentChapter = { title: '', text: '' };

  // Pre-process: join continuation lines (lines ending with \)
  // Handles multi-line headings like "ECONOMIC CONTROL AND\" + "TOTALITARIANISM"
  const joinedLines = [];
  let pendingLine = '';
  for (const line of lines) {
    if (line.trimEnd().endsWith('\\')) {
      pendingLine += line.trimEnd().slice(0, -1) + ' ';
    } else {
      joinedLines.push(pendingLine + line);
      pendingLine = '';
    }
  }
  if (pendingLine) joinedLines.push(pendingLine);

  for (const line of joinedLines) {
    const trimmed = line.trim();
    if (!trimmed) {
      currentChapter.text += '\n';
      continue;
    }

    // Extract plain text for heading detection (v2 cleanAllCss)
    const plainText = cleanAllCss(trimmed);
    // ALL CAPS text between 3-100 chars (typical chapter title)
    const isAllCaps = /^[A-Z][A-Z\s"',:;!?\d\u2014\u2013()\/.&-]*$/.test(plainText);
    const isHeadingLength = plainText.length >= 3 && plainText.length <= 100;

    // Heading indicators:
    // 1) Line has .bold CSS class (Calibre bold-styled headings)
    // 2) Line starts with [ and has anchor link pattern (pandoc EPUB links)
    const hasBoldCss = /\.bold/.test(trimmed);
    const isAnchorLink = trimmed.startsWith('[') && (/\]\(#[^)]+\)/.test(trimmed) || /\]\{#[^}]+\}/.test(trimmed));
    const isShortEnough = plainText.length <= 100;

    const isHeadingLine = isAllCaps && isHeadingLength && isShortEnough && (hasBoldCss || isAnchorLink);

    if (isHeadingLine) {
      if (currentChapter.text.trim().length > 500) {
        rawChapters.push({
          title: cleanTitle(currentChapter.title),
          text: currentChapter.text.trim()
        });
      }
      currentChapter = { title: plainText, text: '' };
    } else {
      currentChapter.text += line + '\n';
    }
  }

  if (currentChapter.text.trim().length > 500) {
    rawChapters.push({
      title: cleanTitle(currentChapter.title || 'Untitled'),
      text: currentChapter.text.trim()
    });
  }

  // Post-process: merge chapter number word headings with following title
  // e.g. [{title:"ONE", text:""}, {title:"THE ABANDONED ROAD", text:"..."}]
  // -> [{title:"THE ABANDONED ROAD", text:"..."}]
  const merged = [];
  for (let i = 0; i < rawChapters.length; i++) {
    const ch = rawChapters[i];
    if (NUMBER_WORDS.has(ch.title.toUpperCase().trim()) && i + 1 < rawChapters.length) {
      // Number word heading. prepend its text to the next chapter
      rawChapters[i + 1].text = (ch.text ? ch.text + '\n' : '') + rawChapters[i + 1].text;
    } else {
      merged.push(ch);
    }
  }
  rawChapters = merged;
}

// Final fallback: single chapter
if (rawChapters.length === 0) {
  rawChapters = [{ title: bookTitle, text: markdown.trim() }];
}

// 4. Classify and filter
const chapters = [];
let chapterNum = 0;

for (const raw of rawChapters) {
  // Skip non-content
  if (skipPatterns.test(raw.title)) continue;
  if (raw.text.length < 800 && raw.title === 'Untitled') continue;

  const isSection = sectionPatterns.test(raw.title);

  if (isSection) {
    chapters.push({
      num: null,
      chapterNum: null,
      title: raw.title,
      text: raw.text,
      isSection: true
    });
  } else {
    chapterNum++;
    chapters.push({
      num: chapterNum,
      chapterNum: chapterNum,
      title: raw.title,
      text: raw.text,
      isSection: false
    });
  }
}

// Estimate tokens and clean text
for (const ch of chapters) {
  ch.estimatedTokens = Math.ceil(ch.text.length / 4);
  ch.totalChapters = chapterNum;
  // Clean CSS artifacts from chapter text
  ch.text = ch.text.replace(/\[\]\{[^}]*\}/g, '');
  let prevText = '';
  while (prevText !== ch.text) {
    prevText = ch.text;
    ch.text = ch.text.replace(/\[([^\[\]]*)\]\{\.bold1?\}/g, '**$1**');
    ch.text = ch.text.replace(/\[([^\[\]]*)\]\{\.italic\}/g, '*$1*');
    ch.text = ch.text.replace(/\[([^\[\]]*)\]\{[^}]*\}/g, '$1');
  }
  ch.text = ch.text.replace(/\{[^}]*\}/g, '');
  ch.text = ch.text.replace(/\[\]/g, '');
  // Strip pandoc fenced div markers
  ch.text = ch.text.replace(/^:{3,}\s*(\{[^}]*\})?\s*$/gm, '');
  // Strip pandoc raw HTML blocks
  ch.text = ch.text.replace(/`<[^>]+>`\{=html\}/g, '');
  // Strip anchor links
  ch.text = ch.text.replace(/\[([^\]]+)\]\(#[a-zA-Z0-9._:\/-]+\)/gi, '$1');
  // Strip internal link IDs
  ch.text = ch.text.replace(/\[([^\]]+)\]\([^)]*\)/g, '$1');
  // Strip bare brackets left over
  ch.text = ch.text.replace(/\[([^\]]*)\]/g, '$1');
  // Collapse whitespace
  ch.text = ch.text.replace(/\n{3,}/g, '\n\n').trim();
}

return [{ json: {
  ...item,
  _bookTitle: bookTitle,
  _bookAuthor: bookAuthor,
  _bookLanguage: bookLanguage,
  _bookDate: bookDate,
  _chapters: chapters,
  _chapterCount: chapterNum,
  _sectionCount: chapters.filter(c => c.isSection).length,
  _totalChars: chapters.reduce((sum, ch) => sum + ch.text.length, 0),
  _fileName: fileName
}}];

