// cleanTitle. Strip Calibre/Pandoc HTML artifacts (loop handles nesting)
function cleanTitle(raw) {
  let t = raw;
  let prev = '';
  while (prev !== t) {
    prev = t;
    t = t.replace(/\[([^\[\]]*)\]\{[^}]*\}/g, '$1');
  }
  t = t.replace(/\{[^}]*\}/g, '');
  t = t.replace(/\[([^\]]*)\]\([^)]*\)/g, '$1');
  t = t.replace(/\s+/g, ' ').trim();
  t = t.replace(/^[#\s]+/, '').replace(/\s+$/, '');
  // Don't strip "Chapter N" prefix here. we need it for splitting logic
  return t || 'Untitled';
}

// stripChapterPrefix. Remove "Chapter N:" prefix for display titles
function stripChapterPrefix(title) {
  return title.replace(/^CHAPTER\s+\d+[\s:\u2014\u2013-]*/i, '').trim() || title;
}

