// Sections to KEEP as untranslated frontmatter (pass through as-is)
// Note: dedication and epigraph moved OUT of frontmatter. they should be translated like content
const frontmatterPatterns = /^(copyright|title\s*page|table\s*of\s*contents|contents)$/i;

// 1. Convert EPUB to markdown + extract media (for cover)
const mediaDir = `/tmp/epub_media_${Date.now()}`;
let markdown;
try {
  markdown = execFileSync('pandoc', [filePath, '-t', 'markdown', '--wrap=none', `--extract-media=${mediaDir}`],
    { encoding: 'utf8', timeout: 120000, maxBuffer: 50 * 1024 * 1024 });
} catch (e) {
  throw new Error('Pandoc EPUB conversion failed: ' + e.message);
}

// 2. Find cover image in extracted media
let coverPath = '';
try {
  if (fs.existsSync(mediaDir)) {
    const findCover = (dir) => {
      let entries;
      try { entries = fs.readdirSync(dir, { withFileTypes: true }); } catch(e) { return null; }
      for (const entry of entries) {
        const full = dir + '/' + entry.name;
        if (entry.isDirectory()) {
          const found = findCover(full);
          if (found) return found;
        } else if (/cover/i.test(entry.name) && /\.(jpg|jpeg|png|gif)$/i.test(entry.name)) {
          return full;
        }
      }
      for (const entry of entries) {
        if (!entry.isDirectory() && /\.(jpg|jpeg|png|gif)$/i.test(entry.name)) {
          return dir + '/' + entry.name;
        }
      }
      for (const entry of entries) {
        if (entry.isDirectory()) {
          const found = findCover(dir + '/' + entry.name);
          if (found) return found;
        }
      }
      return null;
    };
    coverPath = findCover(mediaDir) || '';
  }
} catch(e) {}

// 3. Extract metadata from EPUB OPF (reliable method)
let bookTitle = '', bookAuthor = '', bookLanguage = 'en', bookDate = '';
try {
  // Read OPF directly from EPUB zip using python3 (zipfile)
  const metaScript = `
import zipfile, re, sys, json
with zipfile.ZipFile(sys.argv[1]) as z:
    opf = None
    for name in z.namelist():
        if name.endswith('.opf'):
            opf = z.read(name).decode('utf-8')
            break
    result = {}
    if opf:
        tm = re.search(r'<dc:title[^>]*>([^<]+)</dc:title>', opf)
        if tm: result['title'] = tm.group(1).strip()
        am = re.search(r'<dc:creator[^>]*>([^<]+)</dc:creator>', opf)
        if am: result['author'] = am.group(1).strip()
        lm = re.search(r'<dc:language[^>]*>([^<]+)</dc:language>', opf)
        if lm: result['lang'] = lm.group(1).strip()[:2]
        dm = re.search(r'<dc:date[^>]*>([^<]+)</dc:date>', opf)
        if dm: result['date'] = dm.group(1).strip()
    print(json.dumps(result))
`;
  const metaPyPath = `/tmp/epub_meta_${Date.now()}.py`;
  fs.writeFileSync(metaPyPath, metaScript);
  const metaJson = execFileSync('python3', [metaPyPath, filePath], { encoding: 'utf8', timeout: 10000 });
  try { fs.unlinkSync(metaPyPath); } catch(e) {}
  const metaObj = JSON.parse(metaJson.trim());
  if (metaObj.title) bookTitle = metaObj.title;
  if (metaObj.author) bookAuthor = metaObj.author;
  if (metaObj.lang) bookLanguage = metaObj.lang;
  if (metaObj.date) bookDate = metaObj.date;
} catch(e) {}

// Fallback: try YAML frontmatter in markdown
if (!bookTitle || !bookAuthor) {
  const yamlMatch = markdown.match(/^---\n([\s\S]*?)\n---\n/);
  if (yamlMatch) {
    const yamlBlock = yamlMatch[1];
    if (!bookTitle) { const m = yamlBlock.match(/title:\s*['"]?(.+?)['"]?\s*$/m); if (m) bookTitle = m[1].trim(); }
    if (!bookAuthor) { const m = yamlBlock.match(/(?:author|creator):\s*['"]?(.+?)['"]?\s*$/m); if (m) bookAuthor = m[1].trim(); }
    markdown = markdown.replace(/^---\n[\s\S]*?\n---\n/, '');
  }
}

// Fallback: parse filename (strip nc_ prefix, z-lib tags)
if (!bookTitle || !bookAuthor) {
  let fn = fileName.replace(/\.epub$/i, '');
  fn = fn.replace(/^nc_\d+_[a-z0-9]+_/i, '');  // Strip n8n pipeline prefix
  fn = fn.replace(/\s*\(Z[- ]?Lib(?:rary)?[^)]*\)/gi, '').replace(/\s*\(z-lib[^)]*\)/gi, '');
  const parenMatch = fn.match(/^(.+?)\s*\(([^)]+)\)\s*$/);
  if (parenMatch) {
    if (!bookTitle) bookTitle = parenMatch[1].trim();
    if (!bookAuthor) bookAuthor = parenMatch[2].trim();
  } else if (!bookTitle) {
    bookTitle = fn.trim();
  }
}
bookTitle = bookTitle.replace(/\s+/g, ' ').trim();

const flags = item._flags || prepareData._flags || {};
let targetLang = flags.translate || 'fr';
if (bookLanguage === targetLang) {
  targetLang = bookLanguage === 'fr' ? 'en' : 'fr';
}

// 4. Parse headings. try H1 first, fall back to H2 if no H1 content found
const lines = markdown.split('\n');

// splitByHeadingLevel. Parse markdown into sections at a given heading level
// @param {string[]} lines - All markdown lines
// @param {number} level - Heading level (1 for #, 2 for ##)
// @returns {Array} sections with lineNum, rawTitle, cleanedTitle, text, type
function splitByHeadingLevel(lines, level) {
  const prefix = '#'.repeat(level) + ' ';
  const regex = new RegExp('^' + '#'.repeat(level) + ' (.+)$');
  const sections = [];
  let currentSection = { lineNum: -1, rawTitle: '', cleanedTitle: '', text: '', type: 'pre-heading' };

  for (let i = 0; i < lines.length; i++) {
    const match = lines[i].match(regex);
    // Make sure it's exactly this level, not a deeper heading
    const isExactLevel = lines[i].startsWith(prefix) && (level === 1 || !lines[i].startsWith('#'.repeat(level + 1) + ' '));
    if (match && isExactLevel) {
      if (currentSection.text.trim()) {
        sections.push({ ...currentSection, text: currentSection.text.trim() });
      }
      const rawTitle = match[1].trim();
      const cleaned = cleanTitle(rawTitle);
      currentSection = { lineNum: i, rawTitle, cleanedTitle: cleaned, text: '', type: 'unknown' };
    } else {
      currentSection.text += lines[i] + '\n';
    }
  }
  if (currentSection.text.trim()) {
    sections.push({ ...currentSection, text: currentSection.text.trim() });
  }
  return sections;
}

// Try H1 first
let allH1Sections = splitByHeadingLevel(lines, 1);
// Count actual content sections (not just pre-heading)
const h1ContentSections = allH1Sections.filter(s => s.type !== 'pre-heading' && s.cleanedTitle);

// If 0-1 H1 sections, try H2 as chapter markers
if (h1ContentSections.length <= 1) {
  const h2Sections = splitByHeadingLevel(lines, 2);
  const h2ContentSections = h2Sections.filter(s => s.type !== 'pre-heading' && s.cleanedTitle);
  if (h2ContentSections.length > h1ContentSections.length) {
    allH1Sections = h2Sections;
  }
}

// Fallback 3: Calibre CSS headings (no H1/H2 in pandoc output)
// Some EPUBs use CSS bold spans or anchor links instead of semantic headings.
{
  const contentSections = allH1Sections.filter(s => s.type !== 'pre-heading' && s.cleanedTitle);
  if (contentSections.length <= 1) {
    // cleanAllCss v2. Strip ALL CSS/anchor/HTML artifacts to get plain text
    // Key fix: strip {...} FIRST before bracket patterns (handles deep nesting)
    function cleanAllCssLocal(line) {
      let t = line.trim();
      t = t.replace(/`<[^>]+>`\{=html\}/g, '');
      // v2: Strip ALL {...} attributes FIRST
      t = t.replace(/\{[^}]*\}/g, '');
      // Strip anchor links [text](#ref)
      t = t.replace(/\[([^\]]*)\]\(#[^)]*\)/g, '$1');
      // Strip ALL remaining brackets
      t = t.replace(/\[/g, '').replace(/\]/g, '');
      t = t.replace(/\(#[^)]*\)/g, '');
      t = t.replace(/\^\d+\^/g, '');
      t = t.replace(/\\$/g, '');
      t = t.replace(/\s+/g, ' ').trim();
      return t;
    }

    // Number words for chapter number detection
    const NUMBER_WORDS_T = new Set([
      'ONE', 'TWO', 'THREE', 'FOUR', 'FIVE', 'SIX', 'SEVEN', 'EIGHT', 'NINE', 'TEN',
      'ELEVEN', 'TWELVE', 'THIRTEEN', 'FOURTEEN', 'FIFTEEN', 'SIXTEEN', 'SEVENTEEN',
      'EIGHTEEN', 'NINETEEN', 'TWENTY', 'TWENTY-ONE', 'TWENTY-TWO', 'TWENTY-THREE',
      'TWENTY-FOUR', 'TWENTY-FIVE'
    ]);

    const cssSections = [];
    let curSec = { lineNum: -1, rawTitle: '', cleanedTitle: '', text: '', type: 'pre-heading' };

    // Pre-process: join continuation lines (lines ending with \)
    const joinedLinesT = [];
    let pendingLineT = '';
    for (const line of lines) {
      if (line.trimEnd().endsWith('\\')) {
        pendingLineT += line.trimEnd().slice(0, -1) + ' ';
      } else {
        joinedLinesT.push(pendingLineT + line);
        pendingLineT = '';
      }
    }
    if (pendingLineT) joinedLinesT.push(pendingLineT);

    for (let i = 0; i < joinedLinesT.length; i++) {
      const trimmed = joinedLinesT[i].trim();
      if (!trimmed) { curSec.text += '\n'; continue; }

      const plainText = cleanAllCssLocal(trimmed);
      const isAllCaps = /^[A-Z][A-Z\s"',:;!?\d\u2014\u2013()\/.&-]*$/.test(plainText);
      const isHeadingLength = plainText.length >= 3 && plainText.length <= 100;
      const hasBoldCss = /\.bold/.test(trimmed);
      const isAnchorLink = trimmed.startsWith('[') && (/\]\(#[^)]+\)/.test(trimmed) || /\]\{#[^}]+\}/.test(trimmed));

      const isHeadingLine = isAllCaps && isHeadingLength && (hasBoldCss || isAnchorLink);

      if (isHeadingLine) {
        if (curSec.text.trim()) {
          cssSections.push({ ...curSec, text: curSec.text.trim() });
        }
        curSec = { lineNum: i, rawTitle: plainText, cleanedTitle: cleanTitle(plainText), text: '', type: 'unknown' };
      } else {
        curSec.text += joinedLinesT[i] + '\n';
      }
    }
    if (curSec.text.trim()) {
      cssSections.push({ ...curSec, text: curSec.text.trim() });
    }

    // Post-process: merge number word headings with following title
    const mergedCss = [];
    for (let mi = 0; mi < cssSections.length; mi++) {
      const sec = cssSections[mi];
      if (sec.cleanedTitle && NUMBER_WORDS_T.has(sec.cleanedTitle.toUpperCase().trim()) && mi + 1 < cssSections.length) {
        cssSections[mi + 1].text = (sec.text ? sec.text + '\n' : '') + cssSections[mi + 1].text;
      } else {
        mergedCss.push(sec);
      }
    }
    const finalCssSections = mergedCss;
    const cssContentSections = finalCssSections.filter(s => s.type !== 'pre-heading' && s.cleanedTitle);
    if (cssContentSections.length > contentSections.length) {
      allH1Sections = finalCssSections;
    }
  }
}

// 5. Classify each section
// Detect "Chapter N" pattern for this book
const chapterPattern = /^(chapter\s+\d+|chapitre\s+\d+)$/i;
const isChapterTitle = (title) => chapterPattern.test(title) || /^untitled$/i.test(title);

for (const sec of allH1Sections) {
  if (sec.type === 'pre-heading') {
    sec.type = 'frontmatter';  // Content before any heading
  } else if (hardSkipPatterns.test(sec.cleanedTitle)) {
    sec.type = 'skip';
  } else if (frontmatterPatterns.test(sec.cleanedTitle)) {
    sec.type = 'frontmatter';
  } else if (isChapterTitle(sec.cleanedTitle) && sec.text.trim().length < 200) {
    // "Chapter N" with very little text. it's just a chapter number heading
    // The actual chapter title follows as the next H1
    sec.type = 'chapter-number';
  } else {
    sec.type = 'content';  // Real chapter content or section
  }
}

// 6. Build chapters by merging: Chapter N heading + title heading + sub-sections
// Logic: a "Chapter N" or chapter-title heading starts a new chapter.
// Sub-sections (PREREQUISITES, EMPIRICAL EVIDENCE, etc.) belong to the previous chapter.
const chapters = [];
let frontmatterParts = [];
let currentChapter = null;

for (let i = 0; i < allH1Sections.length; i++) {
  const sec = allH1Sections[i];

  if (sec.type === 'frontmatter' || sec.type === 'pre-heading') {
    frontmatterParts.push(sec);
    continue;
  }
  if (sec.type === 'skip') continue;

  if (sec.type === 'chapter-number') {
    // This is "Chapter N". start new chapter, use next section's title
    if (currentChapter) {
      chapters.push(currentChapter);
    }
    // Look ahead for the chapter title (next H1 that's content type)
    let chTitle = sec.cleanedTitle;
    if (i + 1 < allH1Sections.length && allH1Sections[i + 1].type === 'content') {
      chTitle = stripChapterPrefix(allH1Sections[i + 1].cleanedTitle);
    }
    currentChapter = {
      title: chTitle,
      text: sec.text.trim(),
      imageRefs: []
    };
    continue;
  }

  // Content section
  if (sec.cleanedTitle.match(/^(PREFACE|PRÉFACE|INTRODUCTION|FOREWORD|AVANT-PROPOS|PROLOGUE)$/i)) {
    // Preface/Introduction = its own chapter
    if (currentChapter) chapters.push(currentChapter);
    currentChapter = {
      title: sec.cleanedTitle,
      text: sec.text.trim(),
      imageRefs: []
    };
    continue;
  }

  // Check if this is a chapter title (follows a chapter-number)
  if (i > 0 && allH1Sections[i - 1].type === 'chapter-number') {
    // This is the title for the chapter we just started
    if (currentChapter) {
      currentChapter.title = stripChapterPrefix(sec.cleanedTitle);
      currentChapter.text += '\n\n' + sec.text.trim();
    }
    continue;
  }

  // Check if this looks like a new real chapter (not just a sub-section)
  // Heuristic: if the cleaned title matches a known chapter title pattern from the CONTENTS
  // For now: sub-sections (ALL CAPS) get merged into current chapter as ## headings
  // Sub-sections (ALL CAPS, short text) get merged into current chapter as ## headings
  // BUT: titles starting with "CHAPTER N" are always new chapters, never sub-sections
  // Also: sections with substantial text (>5000 chars) are real chapters, not sub-sections
  const startsWithChapterN = /^CHAPTER\s+\d+/i.test(sec.cleanedTitle);
  const isAllCaps = sec.cleanedTitle === sec.cleanedTitle.toUpperCase() && sec.cleanedTitle.length > 3;
  const hasSubstantialText = sec.text.trim().length > 5000;
  const isSubSection = isAllCaps && !startsWithChapterN && !hasSubstantialText;

  if (isSubSection && currentChapter) {
    // Sub-section: merge into current chapter as H2
    currentChapter.text += `\n\n## ${sec.cleanedTitle}\n\n${sec.text.trim()}`;
  } else {
    // New chapter
    if (currentChapter) chapters.push(currentChapter);
    currentChapter = {
      title: stripChapterPrefix(sec.cleanedTitle),
      text: sec.text.trim(),
      imageRefs: []
    };
  }
}
if (currentChapter) chapters.push(currentChapter);

// 7. Build frontmatter text (copyright, dedication, etc.)
let frontmatterText = '';
for (const fm of frontmatterParts) {
  if (fm.cleanedTitle && fm.type !== 'pre-heading') {
    frontmatterText += `\n\n## ${fm.cleanedTitle}\n\n`;
  }
  frontmatterText += fm.text + '\n';
}
frontmatterText = frontmatterText.trim();

// 8. Clean chapters (same CSS artifact cleanup as before)
const finalChapters = [];
let chapterNum = 0;
for (const ch of chapters) {
  if (ch.text.length < 100) continue;  // Skip near-empty chapters
  chapterNum++;
  let cleanedText = ch.text;
  // Strip empty anchor spans
  cleanedText = cleanedText.replace(/\[\]\{[^}]*\}/g, '');
  // Convert Calibre CSS classes to markdown emphasis
  let prevText = '';
  while (prevText !== cleanedText) {
    prevText = cleanedText;
    cleanedText = cleanedText.replace(/\[([^\[\]]*)\]\{\.bold1?\}/g, '**$1**');
    cleanedText = cleanedText.replace(/\[([^\[\]]*)\]\{\.italic\}/g, '*$1*');
    cleanedText = cleanedText.replace(/\[([^\[\]]*)\]\{[^}]*\}/g, '$1');
  }
  cleanedText = cleanedText.replace(/\{[^}]*\}/g, '');
  cleanedText = cleanedText.replace(/\[\]/g, '');
  // Strip pandoc fenced div markers
  cleanedText = cleanedText.replace(/^:{3,}\s*(\{[^}]*\})?\s*$/gm, '');
  // Strip internal anchor links
  cleanedText = cleanedText.replace(/\[([^\]]+)\]\(#[a-zA-Z0-9._:\/-]+\)/gi, '$1');
  // Extract image references and replace with placeholders
  const imageRefs = [];
  cleanedText = cleanedText.replace(/!\[([^\]]*)\]\([^)]+\)/g, (match) => {
    const idx = imageRefs.length;
    imageRefs.push(match);
    return `{{IMAGE_${idx}}}`;
  });
  cleanedText = cleanedText.replace(/\n{3,}/g, '\n\n').trim();
  // Skip extremely long chapters (>300K chars ≈ 75K tokens, would overflow LLM context)
  // Note: chapters 100-300K may produce truncated translations. future improvement: split at paragraph boundaries
  if (cleanedText.length > 300000) continue;

  // Clean the title too
  let cleanedTitle = ch.title;
  let pt = '';
  while (pt !== cleanedTitle) {
    pt = cleanedTitle;
    cleanedTitle = cleanedTitle.replace(/\[([^\[\]]*)\]\{[^}]*\}/g, '$1');
  }
  cleanedTitle = cleanedTitle.replace(/\{[^}]*\}/g, '').replace(/\s+/g, ' ').trim();

  finalChapters.push({
    num: chapterNum,
    title: cleanedTitle,
    text: cleanedText,
    charCount: cleanedText.length,
    imageRefs: imageRefs
  });
}

// Fallback: if no chapters found, use entire markdown
if (finalChapters.length === 0) {
  finalChapters.push({ num: 1, title: bookTitle, text: markdown.trim(), charCount: markdown.length, imageRefs: [] });
}

// Build text sample for glossary building
let allText = '';
for (const ch of finalChapters) {
  allText += `\n\n--- ${ch.title} ---\n\n` + ch.text;
  if (allText.length > 40000) break;
}

const langNames = { 'fr': 'French', 'en': 'English', 'nl': 'Dutch', 'de': 'German', 'es': 'Spanish' };

// Copy cover to persistent location
let persistentCoverPath = coverPath;
if (coverPath && fs.existsSync(coverPath)) {
  const pipeDir = '/home/node/.n8n/pipeline-files';
  try { if (!fs.existsSync(pipeDir)) fs.mkdirSync(pipeDir, { recursive: true }); } catch(e) {}
  const coverExt = coverPath.match(/\.(jpg|jpeg|png|gif)$/i)?.[0] || '.jpg';
  persistentCoverPath = `${pipeDir}/cover_${Date.now()}${coverExt}`;
  fs.copyFileSync(coverPath, persistentCoverPath);
}

return [{ json: {
  ...item,
  _bookTitle: bookTitle,
  _bookAuthor: bookAuthor,
  _bookLanguage: bookLanguage,
  _bookDate: bookDate,
  _sourceLang: bookLanguage,
  _targetLang: targetLang,
  _sourceLangName: langNames[bookLanguage] || bookLanguage,
  _targetLangName: langNames[targetLang] || targetLang,
  _coverPath: persistentCoverPath,
  _mediaDir: mediaDir,
  _frontmatterText: frontmatterText,
  _chapters: finalChapters,
  _chapterCount: chapterNum,
  _totalChars: finalChapters.reduce((sum, ch) => sum + ch.charCount, 0),
  _textSample: allText.substring(0, 40000),
  _fileName: fileName,
  _filePath: filePath,
  _contentType: 'translate-book'
}}];

// pass 0: extract a bilingual glossary before translating
// Qwen scans sample text to keep terminology consistent across chapters

const item = $input.first().json;

const sourceLang = item._sourceLangName || 'English';
const targetLang = item._targetLangName || 'French';
const textSample = item._textSample || '';

if (!textSample || textSample.length < 500) {
  // No text to analyze, skip glossary
  return [{ json: { ...item, _glossary: [], _glossaryText: '' } }];
}

const systemPrompt = `You are a professional book translator preparing a translation glossary from ${sourceLang} to ${targetLang}.

Analyze this book text and extract a translation glossary.

For each term, provide:
- source: the term in the original language
- target: the preferred translation in ${targetLang}
- context: brief note on usage

Focus on:
1. Proper nouns (people, places, organizations) — decide if they should be translated or kept as-is
2. Technical/domain-specific terms that need consistent translation
3. Recurring phrases or concepts central to the book's argument
4. Idiomatic expressions that need careful handling

Output as JSON array: [{"source": "...", "target": "...", "context": "..."}]
Return 20-50 terms maximum. Output ONLY the JSON array, nothing else.`;

const { spawn: _spawn } = require("child_process");
const _fs = require("fs");
const _tmpIn = "/tmp/llm_glossary_" + Date.now() + ".json";
const _tmpOut = "/tmp/llm_glossary_resp_" + Date.now() + ".json";
_fs.writeFileSync(_tmpIn, JSON.stringify({
  model: 'qwen3.5-122b',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: textSample }
  ],
  temperature: 0.3,
  max_tokens: 4000
}));
await new Promise((resolve, reject) => {
  const proc = _spawn("wget", [
    "-q", "-O", _tmpOut,
    "--timeout=7200",
    "--header=Content-Type: application/json",
    "--post-file=" + _tmpIn,
    "http://YOUR_HOST_IP:8081/v1/chat/completions"
  ], { stdio: "ignore" });
  proc.on("close", (code) => {
    if (code === 0) resolve();
    else reject(new Error("wget glossary exited with code " + code));
  });
  proc.on("error", reject);
});
const response = JSON.parse(_fs.readFileSync(_tmpOut, "utf8"));
try { _fs.unlinkSync(_tmpIn); } catch(e) {}
try { _fs.unlinkSync(_tmpOut); } catch(e) {}

let glossary = [];
let glossaryText = '';

if (response?.choices?.[0]?.message?.content) {
  let raw = response.choices[0].message.content.trim();
  // Strip think tags
  raw = raw.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
  // Extract JSON array
  const jsonMatch = raw.match(/\[[\s\S]*\]/);
  if (jsonMatch) {
    try {
      glossary = JSON.parse(jsonMatch[0]);
      // Build human-readable glossary for injection into translation prompts
      glossaryText = glossary.map(g => 
        `- "${g.source}" → "${g.target}" (${g.context || ''})`
      ).join('\n');
    } catch(e) {
      // JSON parsing failed, use raw text
      glossaryText = raw;
    }
  }
}

return [{ json: {
  ...item,
  _glossary: glossary,
  _glossaryText: glossaryText,
  _glossaryCount: glossary.length
}}];

// TEaR 3-pass: Translate, Evaluate, Revise
// after all chapters translated, swaps model back to daily driver

const item = $input.first().json;

const chapters = item._chapters || [];
const glossaryText = item._glossaryText || '';
const sourceLang = item._sourceLangName || 'English';
const targetLang = item._targetLangName || 'French';
const bookTitle = item._bookTitle || 'Book';
const bookAuthor = item._bookAuthor || 'Unknown';

const LLM_URL = 'http://YOUR_HOST_IP:8081/v1/chat/completions';
const DAILY_MODEL = 'qwen3.5-35b-nothink';
const MAX_RETRIES = 3;
const RETRY_DELAY_MS = 45000; // 45s between retries (model loading takes time)

// Test parameter overrides. read from pipeline_queue metadata or item._testParams
const testParams = item._testParams || {};
const LLM_MODEL = testParams.model || 'qwen3.5-122b';
const TRANSLATE_TEMP = testParams.translateTemp ?? 0.3;
const EVALUATE_TEMP = testParams.evaluateTemp ?? 0.1;
const REVISE_TEMP = testParams.reviseTemp ?? 0.2;
const TOP_P = testParams.topP ?? null;  // null = use model default
const TEST_ID = testParams.testId || '';  // e.g., "test-01-qwen122b"
const MAX_CHAPTERS = testParams.maxChapters ?? 0;  // 0 = translate all chapters

console.log(`[Config] Model: ${LLM_MODEL}, Translate temp: ${TRANSLATE_TEMP}, Evaluate temp: ${EVALUATE_TEMP}, Revise temp: ${REVISE_TEMP}, Top-P: ${TOP_P || 'default'}, Test: ${TEST_ID || 'none'}`);

// sleep helper
const sleep = (ms) => new Promise(resolve => setTimeout(resolve, ms));

// callLLM. Non-blocking LLM call using wget + spawn (keeps event loop alive for heartbeats)
// @param {string} system - System prompt
// @param {string} user - User prompt
// @param {number} maxTokens - Max response tokens
// @param {number} temperature - Sampling temperature
// @param {string} model - Model name override (default: LLM_MODEL)
// @param {number|null} topP - Top-P sampling parameter (null = model default)
// @returns {string} The LLM response text (think tags stripped)
const callLLM = async (system, user, maxTokens = 32000, temperature = 0.1, model = LLM_MODEL, topP = TOP_P) => {
  const { spawn } = require("child_process");
  const fs = require("fs");
  let lastError;
  for (let attempt = 1; attempt <= MAX_RETRIES; attempt++) {
    try {
      const tmpIn = "/tmp/llm_req_" + Date.now() + "_" + attempt + ".json";
      const tmpOut = "/tmp/llm_resp_" + Date.now() + "_" + attempt + ".json";
      const reqBody = {
        model: model,
        messages: [
          { role: "system", content: system },
          { role: "user", content: user }
        ],
        temperature,
        max_tokens: maxTokens
      };
      // Add top_p if specified (null = use model default)
      if (topP !== null && topP !== undefined) {
        reqBody.top_p = topP;
      }
      const body = JSON.stringify(reqBody);
      fs.writeFileSync(tmpIn, body);
      // spawn + Promise keeps event loop alive so JS Task Runner heartbeat doesn't fail
      await new Promise((resolve, reject) => {
        const proc = spawn("wget", [
          "-q", "-O", tmpOut,
          "--timeout=7200",
          "--header=Content-Type: application/json",
          "--post-file=" + tmpIn,
          LLM_URL
        ], { stdio: "ignore" });
        proc.on("close", (code) => {
          if (code === 0) resolve();
          else reject(new Error("wget exited with code " + code));
        });
        proc.on("error", reject);
      });
      const raw = fs.readFileSync(tmpOut, "utf8");
      try { fs.unlinkSync(tmpIn); } catch(e) {}
      try { fs.unlinkSync(tmpOut); } catch(e) {}
      const response = JSON.parse(raw);
      let text = response?.choices?.[0]?.message?.content?.trim() || "";
      // Strip thinking tags from Qwen output
      text = text.replace(/<think>[\s\S]*?<\/think>/g, "").trim();
      if (text) return text;
      lastError = new Error("Empty LLM response");
    } catch (err) {
      lastError = err;
    }
    if (attempt < MAX_RETRIES) {
      await sleep(RETRY_DELAY_MS);
    }
  }
  throw lastError;
};

const translatedChapters = [];
let previousTranslation = '';
const chapterTimings = [];  // Per-chapter timing data
const translationStartTime = Date.now();

// Limit chapters for test runs (0 = translate all)
const chaptersToTranslate = MAX_CHAPTERS > 0 ? chapters.slice(0, MAX_CHAPTERS) : chapters;
if (MAX_CHAPTERS > 0) {
  console.log(`[Test] Limiting to first ${MAX_CHAPTERS} chapters (of ${chapters.length} total)`);
}

for (let i = 0; i < chaptersToTranslate.length; i++) {
  const ch = chapters[i];
  const chapterStartTime = Date.now();

  // Context from previous chapter for style/terminology continuity
  let contextOverlap = '';
  if (previousTranslation && previousTranslation.length > 100) {
    const words = previousTranslation.split(/\s+/);
    contextOverlap = words.slice(-500).join(' ');
  }

  // ========== PASS 1: TRANSLATE ==========
  const translateSystem = `You are a professional literary translator specializing in ${sourceLang}-to-${targetLang} translation.
You have 20 years of experience translating published books for major ${targetLang} publishers.

${glossaryText ? `GLOSSARY — Use these translations consistently:\n${glossaryText}\n` : ''}
${contextOverlap ? `CONTEXT — End of previous chapter's translation (for continuity):\n${contextOverlap}\n` : ''}
TRANSLATION PRINCIPLES:
- Preserve the author's voice, tone, and writing style above all else
- Use natural, idiomatic ${targetLang} — never literal word-for-word translation
- Adapt cultural references when the ${targetLang} reader would not understand the original
- Maintain the register (formal/informal/colloquial) of the source text
- Preserve paragraph structure, emphasis, and formatting exactly
- For idioms: find the ${targetLang} equivalent, never translate literally
- Do NOT add translator notes, commentary, or footnotes
- Do NOT skip or summarize any content — translate EVERYTHING
- Output ONLY the translated text, nothing else
- Do NOT add a preamble like "Here is the translation"

FORMATTING RULES (critical):
- PRESERVE all markdown formatting exactly: **bold**, *italic*, ## headings, > blockquotes
- Keep {{IMAGE_N}} placeholders exactly as-is — do NOT translate or remove them
- Keep markdown line breaks (backslash at end of line) intact
- Do NOT convert markdown to plain text — keep all asterisks, hashes, etc.`;

  const translateUser = `Translate this chapter:\n\n# ${ch.title}\n\n${ch.text}`;

  console.log(`[TEaR] Chapter ${i+1}/${chapters.length}: "${ch.title}" — Pass 1 (Translate)...`);
  let pass1Text = '';
  try {
    pass1Text = await callLLM(translateSystem, translateUser, 32000, TRANSLATE_TEMP);
    console.log(`[TEaR] Pass 1 done: ${pass1Text.length} chars`);
  } catch(err) {
    console.log(`[TEaR] Pass 1 FAILED: ${err.message}`);
    const fallback = `[TRANSLATION FAILED: ${err.message || 'unknown'}]\n\n${ch.text}`;
    translatedChapters.push({ num: ch.num, originalTitle: ch.title, translatedTitle: ch.title, text: fallback, charCount: fallback.length, passes: 0 });
    chapterTimings.push({ num: ch.num, title: ch.title, durationSec: Math.round((Date.now() - chapterStartTime) / 1000), passes: 0 });
    previousTranslation = '';
    continue;
  }

  if (!pass1Text || pass1Text.length < 50) {
    translatedChapters.push({ num: ch.num, originalTitle: ch.title, translatedTitle: ch.title, text: pass1Text || ch.text, charCount: (pass1Text || ch.text).length, passes: 1 });
    chapterTimings.push({ num: ch.num, title: ch.title, durationSec: Math.round((Date.now() - chapterStartTime) / 1000), passes: 1 });
    previousTranslation = pass1Text || '';
    continue;
  }

  // ========== PASS 2: EVALUATE ==========
  const evaluateSystem = `You are a bilingual editor reviewing a ${sourceLang} to ${targetLang} literary translation.
You have extensive experience in both languages and deep knowledge of translation quality.

Compare the source text against the translation and identify specific issues.

EVALUATION CRITERIA:
1. ACCURACY: Mistranslations, omissions, additions not in the source
2. FLUENCY: Awkward phrasing, unnatural ${targetLang} constructions
3. TERMINOLOGY: Inconsistency with the glossary, wrong technical terms
4. STYLE: Voice/tone mismatch, register shifts, lost nuances
5. FORMATTING: Missing/broken markdown, lost emphasis, heading errors

${glossaryText ? 'GLOSSARY for reference:\n' + glossaryText + '\n' : ''}

OUTPUT FORMAT:
- List each issue as: [CATEGORY] Section/quote → problem → suggested fix
- Be concise and actionable — the translator will use your feedback directly
- Focus on issues that genuinely affect quality — skip trivial nitpicks
- If the translation is excellent with no real issues, respond with exactly: NO_ISSUES_FOUND`;

  const evaluateUser = `SOURCE TEXT (${sourceLang}):\n\n${ch.text}\n\n---\n\nTRANSLATION (${targetLang}):\n\n${pass1Text}`;

  let pass2Text = '';
  console.log(`[TEaR] Chapter ${i+1}/${chapters.length}: Pass 2 (Evaluate)...`);
  try {
    pass2Text = await callLLM(evaluateSystem, evaluateUser, 8000, EVALUATE_TEMP);
    console.log(`[TEaR] Pass 2 done: ${pass2Text.length} chars`);
  } catch(err) {
    console.log(`[TEaR] Pass 2 FAILED (using Pass 1 as final): ${err.message}`);
    // Evaluate failed. use pass 1 as final
  }

  // If no issues found or evaluate failed, skip revise
  if (!pass2Text || pass2Text.includes('NO_ISSUES_FOUND')) {
    console.log(`[TEaR] No issues found — skipping Pass 3`);
    let finalText = pass1Text;
    let translatedTitle = ch.title;
    if (ch.title && ch.title.length > 3 && !/^\d+$/.test(ch.title)) {
      const titleMatch = finalText.match(/^#\s+(.+)$/m);
      if (titleMatch) {
        translatedTitle = titleMatch[1].trim();
        finalText = finalText.replace(/^#\s+.+\n*/, '').trim();
      }
    }
    translatedTitle = translatedTitle.replace(/^\[|\]$/g, '').trim();
    translatedChapters.push({
      num: ch.num, originalTitle: ch.title, translatedTitle,
      text: finalText, charCount: finalText.length,
      passes: pass2Text ? 2 : 1,
      reviewSummary: pass2Text ? 'NO_ISSUES_FOUND' : 'evaluate_skipped'
    });
    chapterTimings.push({ num: ch.num, title: ch.title, durationSec: Math.round((Date.now() - chapterStartTime) / 1000), passes: pass2Text ? 2 : 1 });
    previousTranslation = finalText;
    continue;
  }

  // ========== PASS 3: REVISE ==========
  const reviseSystem = `You are a professional literary translator producing the final published version of a ${sourceLang} to ${targetLang} translation.
You received editorial feedback on your draft. Apply the corrections to produce an improved, polished translation.

${glossaryText ? `GLOSSARY — Use these translations consistently:\n${glossaryText}\n` : ''}
${contextOverlap ? `CONTEXT — End of previous chapter (for continuity):\n${contextOverlap}\n` : ''}

REVISION RULES:
- Apply each piece of editorial feedback carefully and precisely
- Do NOT introduce new errors while fixing identified ones
- Maintain the author's voice and overall translation quality
- If a suggestion would make the text worse, keep the original phrasing
- Preserve ALL markdown formatting: **bold**, *italic*, ## headings, > blockquotes
- Keep {{IMAGE_N}} placeholders exactly as-is
- Output ONLY the complete revised translation — no preamble, no commentary
- Do NOT add "Here is the revised translation" or any similar prefix`;

  const reviseUser = `EDITORIAL FEEDBACK:\n\n${pass2Text}\n\n---\n\nCURRENT TRANSLATION TO REVISE:\n\n${pass1Text}\n\n---\n\nORIGINAL SOURCE (for reference):\n\n${ch.text}`;

  let pass3Text = '';
  console.log(`[TEaR] Chapter ${i+1}/${chapters.length}: Pass 3 (Revise)...`);
  try {
    pass3Text = await callLLM(reviseSystem, reviseUser, 32000, REVISE_TEMP);
    console.log(`[TEaR] Pass 3 done: ${pass3Text.length} chars`);
  } catch(err) {
    console.log(`[TEaR] Pass 3 FAILED (using Pass 1 as final): ${err.message}`);
    // Revise failed. use pass 1
  }

  // Safety: if Revise output is much shorter than Translate output, use Translate
  // This happens when the LLM can't reproduce a full chapter-length text in the revise pass
  if (pass3Text && pass1Text && pass3Text.length < pass1Text.length * 0.5) {
    console.log('[TEaR] Revise output too short (' + pass3Text.length + ' vs ' + pass1Text.length + ' chars), using Pass 1 translation');
    pass3Text = '';
  }

  let finalText = pass3Text || pass1Text;

  // Extract translated title from heading if present
  let translatedTitle = ch.title;
  if (ch.title && ch.title.length > 3 && !/^\d+$/.test(ch.title)) {
    const titleMatch = finalText.match(/^#\s+(.+)$/m);
    if (titleMatch) {
      translatedTitle = titleMatch[1].trim();
      finalText = finalText.replace(/^#\s+.+\n*/, '').trim();
    }
  }
  translatedTitle = translatedTitle.replace(/^\[|\]$/g, '').trim();

  translatedChapters.push({
    num: ch.num, originalTitle: ch.title, translatedTitle,
    text: finalText, charCount: finalText.length,
    passes: pass3Text ? 3 : (pass2Text ? 2 : 1),
    reviewSummary: pass2Text ? pass2Text.substring(0, 500) : 'skipped'
  });

  previousTranslation = finalText;
  const chapterDuration = Math.round((Date.now() - chapterStartTime) / 1000);
  chapterTimings.push({ num: ch.num, title: ch.title, durationSec: chapterDuration, passes: pass3Text ? 3 : 1 });
  console.log(`[TEaR] Chapter ${i+1} complete: ${finalText.length} chars, ${pass3Text ? 3 : 1} passes, ${chapterDuration}s`);
}

