  let cleanFm = frontmatterText
    .replace(/<svg[\s\S]*?<\/svg>/gi, '')
    .replace(/<div[\s\S]*?<\/div>/gi, '')
    .replace(/<nav[\s\S]*?<\/nav>/gi, '')
    .replace(/:::\s*\S+[\s\S]*?:::/g, '')  // pandoc fenced divs
    .replace(/\[?\]\{[^}]*\}/g, '')  // empty anchor spans
    .replace(/!\[[^\]]*\]\([^)]*\)/g, '')  // image references (cover handled separately)
    .replace(/\n{3,}/g, '\n\n')
    .trim();
  if (cleanFm && cleanFm.length > 20) {
    mdContent += cleanFm + '\n\n';
  }
}

for (const ch of chapters) {
