// REPACKAGE EPUB. Fix mimetype entry flags for Calibre compatibility
// Pandoc sets flags=0x0802 (UTF-8 + compression level) on mimetype entry,
// but EPUB spec requires mimetype to have flags=0x0000 for strict readers like Calibre
const repackScript = `
import zipfile
import os
import sys

src = sys.argv[1]
dst = sys.argv[2]

# Read all entries from pandoc EPUB
with zipfile.ZipFile(src, 'r') as zin:
    entries = []
    for info in zin.infolist():
        entries.append((info, zin.read(info.filename)))

# Write new EPUB with clean mimetype entry
with zipfile.ZipFile(dst, 'w') as zout:
    # 1. Write mimetype FIRST, stored, no extra field, flags=0
    mt_info = zipfile.ZipInfo('mimetype')
    mt_info.compress_type = zipfile.ZIP_STORED
    mt_info.external_attr = 0
    mt_info.flag_bits = 0  # Critical: Calibre requires flags=0
    zout.writestr(mt_info, 'application/epub+zip')

    # 2. Write all other entries with deflate
    for info, data in entries:
        if info.filename == 'mimetype':
            continue  # Already written
        new_info = zipfile.ZipInfo(info.filename)
        new_info.compress_type = zipfile.ZIP_DEFLATED
        new_info.external_attr = info.external_attr
        zout.writestr(new_info, data)

# Verify
with zipfile.ZipFile(dst, 'r') as z:
    bad = z.testzip()
    if bad:
        print(f'BAD: {bad}', file=sys.stderr)
        sys.exit(1)
    names = z.namelist()
    assert names[0] == 'mimetype', f'First entry is {names[0]}, expected mimetype'
    info0 = z.infolist()[0]
    assert info0.compress_type == 0, f'mimetype compress_type={info0.compress_type}'
    assert info0.flag_bits == 0, f'mimetype flag_bits={info0.flag_bits}'
    print(f'OK: {len(names)} entries, mimetype flags=0x{info0.flag_bits:04x}')
`;

const repackPyPath = `/tmp/repack_epub_${stamp}.py`;
