    companion += `\n--- Timing ---\n`;
    companion += `Total duration: ${testParams.totalDurationSec || 0}s (${Math.round((testParams.totalDurationSec || 0) / 60)}min)\n`;
    companion += `Chapters: ${timings.length}\n`;
    for (const t of timings) {
      companion += `  Ch ${t.num} "${t.title}": ${t.durationSec}s (${t.passes} passes)\n`;
    }
    companion += `\n--- Book ---\n`;
    companion += `Title: ${item._bookTitle || 'unknown'}\n`;
    companion += `Author: ${bookAuthor}\n`;
    companion += `Source language: ${item._sourceLang || 'unknown'}\n`;
    companion += `Target language: ${targetLang}\n`;
    companion += `Translated title: ${translatedTitle}\n`;
    companion += `Chapter count: ${chapters.length}\n`;
    companion += `Total chars: ${chapters.reduce((s, c) => s + (c.charCount || c.text.length), 0)}\n`;
    companion += `\n--- Translation Method ---\n`;
    companion += `Method: ${item._translationMethod || 'TEaR 3-pass'}\n`;
    companion += `Cover used: ${!!(coverPath && fs.existsSync(coverPath))}\n`;
    companion += `EPUB size: ${epubStat.size} bytes\n`;

    companionPath = `${testsDir}/${testId}.txt`;
    fs.writeFileSync(companionPath, companion, 'utf8');
    console.log(`[Test] Saved test output: ${testEpubPath} + ${companionPath}`);
  } catch(e) {
    console.log(`[Test] Companion file error (non-fatal): ${e.message}`);
  }
}

return [{ json: {
  ...item,
  _epubPath: epubPath,
  _epubSize: epubStat.size,
  _outputFileName: outputName,
  _translatedTitle: translatedTitle,
  _targetLang: targetLang,
  _coverUsed: !!(coverPath && fs.existsSync(coverPath)),
  _debugEpubPath: debugPath,
  _testCompanionPath: companionPath
}}];

// prepare binary with proper n8n API for NextCloud upload

const fs = require('fs');

const item = $input.first().json;
const epubPath = item._epubPath;
const outputName = item._outputFileName;

if (!epubPath || !fs.existsSync(epubPath)) {
  throw new Error('Translated EPUB not found at: ' + epubPath);
}

// Read the EPUB file as a Buffer
const epubBuffer = fs.readFileSync(epubPath);

// Use n8n's prepareBinaryData (handles filesystem-v2 correctly)
const binaryData = await this.helpers.prepareBinaryData(epubBuffer, outputName, 'application/epub+zip');

// Clean up temp file
try { fs.unlinkSync(epubPath); } catch(e) {}

// NOTE: Source EPUB kept for potential reuse by subsequent jobs

return [{
  json: {
    ...item,
    _uploadReady: true,
    _uploadFileName: outputName,
    _uploadSize: epubBuffer.length
  },
  binary: {
    data: binaryData
  }
}];

// build confirmation message for translated book
// references Upload Translated EPUB (NextCloud node doesn't pass through data)

function toBold(text) {
  const boldMap = {};
  for (let i = 0; i < 26; i++) {
    boldMap[String.fromCharCode(65 + i)] = String.fromCodePoint(0x1D5D4 + i);
  }
  for (let i = 0; i < 26; i++) {
    boldMap[String.fromCharCode(97 + i)] = String.fromCodePoint(0x1D5EE + i);
  }
  for (let i = 0; i < 10; i++) {
    boldMap[String.fromCharCode(48 + i)] = String.fromCodePoint(0x1D7EC + i);
  }
  return text.split('').map(c => boldMap[c] || c).join('');
}

// Get data from the Upload node (NC Upload doesn't pass through)
const item = $('Upload Translated EPUB').first().json;
const prepareData = $('Prepare Job').first().json;

const translatedTitle = item._translatedTitle || item._bookTitle || 'Book';
const originalTitle = item._bookTitle || 'Book';
const targetLangName = item._targetLangName || 'French';
const chapterCount = item._chapterCount || 0;
const glossaryCount = item._glossaryCount || 0;
const outputName = item._outputFileName || 'translated.epub';
const uploadSize = item._uploadSize || 0;
const sizeMB = (uploadSize / (1024 * 1024)).toFixed(1);

const langEmojis = { 'fr': '\uD83C\uDDEB\uD83C\uDDF7', 'en': '\uD83C\uDDEC\uD83C\uDDE7', 'nl': '\uD83C\uDDF3\uD83C\uDDF1', 'de': '\uD83C\uDDE9\uD83C\uDDEA', 'es': '\uD83C\uDDEA\uD83C\uDDF8' };
const flag = langEmojis[item._targetLang] || '\uD83C\uDF10';

const response = [
  `\uD83D\uDCDA ${toBold('Book Translation Complete')}`,
  '',
  `${flag} ${toBold(originalTitle)}`,
  `\u2192 ${toBold(translatedTitle)}`,
  '',
  `\uD83D\uDCD6 Chapters translated: ${chapterCount}`,
  `\uD83D\uDCCB Glossary terms: ${glossaryCount}`,
  `\uD83D\uDCE6 Output: ${outputName} (${sizeMB} MB)`,
  '',
  `\u2705 Uploaded to NextCloud Pipeline/Processed/`
].join('\n');

return [{ json: {
  ...item,
  _response: response,
  _senderUuid: prepareData._senderUuid || 'YOUR_UUID',
  _userRole: prepareData._userRole || 'admin',
  _contentKey: `book:translate:${item._fileName || 'unknown'}`,
  _contentType: 'translate-book'
}}];

// move file from Inbox/Translate to Processed on NextCloud
// only runs for NextCloud-sourced jobs

const prepareData = $('Prepare Job').first().json;
const sourceChannel = prepareData._sourceChannel || '';

if (sourceChannel !== 'nextcloud') {
  // Not a NextCloud job. nothing to move
  return [];
}

// Parse metadata to get NC path info
let meta = {};
try { meta = JSON.parse(prepareData._messageText || '{}'); } catch(e) {}

const fileName = meta.fileName || '';
const ncFolder = meta.ncFolder || 'Inbox';
const ncPath = meta.ncPath || `/Shared/Shared/Pipeline/${ncFolder}/${fileName}`;

if (!fileName) {
  // No filename. can't move
  return [];
}

return [{ json: {
  _ncPath: ncPath,
  _fileName: fileName,
  _destPath: `/Shared/Shared/Pipeline/Processed/${fileName}`
}}];

// convert summary to spoken prose for audio narration

const { spawn } = require('child_process');
const fs = require('fs');

const item = $input.first().json;
const flags = item._flags || {};

// Check if TTS is requested
if (!flags.tts && item._contentType !== 'local-book') {
  return [{ json: { ...item, _ttsText: null } }];
}

// Extract summary text, excluding "## Original Content" section
let summaryText = item._summary || '';
const marker = '## Original Content';
const markerIdx = summaryText.indexOf(marker);
if (markerIdx !== -1) {
  summaryText = summaryText.substring(0, markerIdx).trim();
}
// Also strip "## Original Post" section (X posts)
const postMarker = '## Original Post';
const postIdx = summaryText.indexOf(postMarker);
if (postIdx !== -1) {
  summaryText = summaryText.substring(0, postIdx).trim();
}
// Also strip "## Transcript" section (voice notes)
const transcriptMarker = '## Transcript';
const transcriptIdx = summaryText.indexOf(transcriptMarker);
if (transcriptIdx !== -1) {
  summaryText = summaryText.substring(0, transcriptIdx).trim();
}
// Strip trailing --- separator
summaryText = summaryText.replace(/\n---\s*$/, '').trim();
// Sanitize --- separators (Kokoro known issue. causes missing content)
summaryText = summaryText.replace(/\n---+\n/g, '\n\n');

if (!summaryText || summaryText.length < 50) {
  console.log('[TTS Rewrite] Summary too short (' + summaryText.length + ' chars) — skipping TTS');
  return [{ json: { ...item, _ttsText: null } }];
}

// For book digests, narrate only TL;DR + Key Takeaways + Synthesis
// Full book summary (65KB+) exceeds Qwen + Kokoro timeout limits
if (item._contentType === 'local-book') {
  let bookExcerpt = '';
  const tldrMatch = summaryText.match(/\*\*TL;DR:\*\*\s*([\s\S]*?)(?=\n---|\n###)/i);
  const takeawaysMatch = summaryText.match(/### Key Takeaways\s*([\s\S]*?)(?=\n---|\n###\s*Chapter|\n##\s)/i);
  const synthesisMatch = summaryText.match(/### Synthesis\s*([\s\S]*?)$/i);

  if (tldrMatch) bookExcerpt += tldrMatch[1].trim() + '\n\n';
  if (takeawaysMatch) bookExcerpt += '**Key Takeaways:**\n' + takeawaysMatch[1].trim() + '\n\n';
  if (synthesisMatch) bookExcerpt += '**Synthesis:**\n' + synthesisMatch[1].trim();

  if (bookExcerpt.length > 100) {
    console.log('[TTS Rewrite] Book digest — using excerpt (' + bookExcerpt.length + ' chars) instead of full summary (' + summaryText.length + ' chars)');
    summaryText = bookExcerpt.trim();
  }
}

try {
  const systemPrompt = `You are converting a written summary into spoken prose for audio narration.

Rules:
- SAME content, SAME length, SAME depth — change nothing about the information
- Remove all markdown formatting: no headers (###), no bold (**), no bullet points (- or *)
- Remove all structural labels ("TL;DR:", "Key Takeaways:", "Key Points:", "Standout Quotes:", "Key Arguments:", "Relevance & Takeaways:", "Core argument:", "Synthesis:", "Chapter N:")
- Convert lists and bullet points into flowing sentences connected by natural transitions
- Convert numbered sections into narrated prose ("The first important insight is...", "Moving to the next chapter...", "Another key finding is...")
- Write as if narrating for a podcast — natural spoken cadence with smooth transitions between topics
- Preserve all names, numbers, quotes, technical terms, and specific claims exactly
- Do NOT add introductions like "In this summary..." or "Welcome to..." or "Today we'll discuss..."
- Do NOT add conclusions like "In conclusion..." or "To sum up..." or "That's all for..."
- Do NOT shorten or extend the content — match the original length precisely
- Match the language of the input text (if the input is in French, output must be in French)
- For book digests: narrate chapter by chapter in order, maintaining the chapter progression`;

  const tmpIn = '/tmp/tts_rewrite_req_' + Date.now() + '.json';
  const tmpOut = '/tmp/tts_rewrite_resp_' + Date.now() + '.json';

  const reqBody = {
    model: 'qwen3.5-35b-nothink',
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: summaryText }
    ],
    temperature: 0.2,
    max_tokens: 16000
  };
  fs.writeFileSync(tmpIn, JSON.stringify(reqBody));

  // spawn + Promise keeps event loop alive (prevents JS Task Runner heartbeat failure)
  await new Promise((resolve, reject) => {
    const proc = spawn('wget', [
      '-q', '-O', tmpOut,
      '--timeout=600',
      '--header=Content-Type: application/json',
      '--post-file=' + tmpIn,
      'http://llama-swap:8080/v1/chat/completions'
    ], { stdio: 'ignore' });
    proc.on('close', (code) => {
      if (code === 0) resolve();
      else reject(new Error('wget exited with code ' + code));
    });
    proc.on('error', reject);
  });

  const raw = fs.readFileSync(tmpOut, 'utf8');
  try { fs.unlinkSync(tmpIn); } catch(e) {}
  try { fs.unlinkSync(tmpOut); } catch(e) {}

  const response = JSON.parse(raw);
  let ttsText = response?.choices?.[0]?.message?.content?.trim() || '';
  // Strip thinking tags from Qwen output
  ttsText = ttsText.replace(/<think>[\s\S]*?<\/think>/g, '').trim();

  if (!ttsText || ttsText.length < 50) {
    console.log('[TTS Rewrite] Empty/short rewrite result — skipping TTS');
    return [{ json: { ...item, _ttsText: null } }];
  }

  // Final sanitize for Kokoro (--- causes missing content)
  ttsText = ttsText.replace(/---+/g, '');

  console.log('[TTS Rewrite] Success — ' + summaryText.length + ' chars input -> ' + ttsText.length + ' chars output');
  return [{ json: { ...item, _ttsText: ttsText } }];
} catch (err) {
  console.log('[TTS Rewrite] Error: ' + err.message + ' — continuing without TTS');
  return [{ json: { ...item, _ttsText: null } }];
}

// call Kokoro API to generate MP3 from rewritten text

const { spawn } = require('child_process');
const fs = require('fs');

const item = $input.first().json;

if (!item._ttsText) {
  return [{ json: { ...item, _ttsAudioPath: null, _ttsFilename: null, _ttsAudioFolder: null } }];
}

try {
  // Detect language and select voice
  const lang = item._translatedTo || item._language || 'en';
  const voice = lang.startsWith('fr') ? 'ff_siwis' : 'af_heart';

  // Build filename
  const slug = (item._slug || item._title || 'audio')
    .toLowerCase().replace(/[^a-z0-9\s-]/g, '').replace(/\s+/g, '-').substring(0, 60);
  const date = new Date().toISOString().split('T')[0];
  const filename = date + '_' + slug + '.mp3';
  const tempPath = '/tmp/tts_' + Date.now() + '_' + filename;

  // Build Kokoro request
  const reqBody = {
    input: item._ttsText,
    voice: voice,
    response_format: 'mp3'
  };

  const tmpReq = '/tmp/kokoro_req_' + Date.now() + '.json';
  fs.writeFileSync(tmpReq, JSON.stringify(reqBody));

  // Call Kokoro API via wget. binary MP3 saved directly to tempPath
  await new Promise((resolve, reject) => {
    const proc = spawn('wget', [
      '-q', '-O', tempPath,
      '--timeout=600',
      '--header=Content-Type: application/json',
      '--post-file=' + tmpReq,
      'http://kokoro-tts:8880/v1/audio/speech'
    ], { stdio: 'ignore' });
    proc.on('close', (code) => {
      if (code === 0) resolve();
      else reject(new Error('wget exited with code ' + code));
    });
    proc.on('error', reject);
  });

  try { fs.unlinkSync(tmpReq); } catch(e) {}

  // Verify file was created and has content
  const stats = fs.statSync(tempPath);
  if (stats.size < 1000) {
    throw new Error('Generated audio too small (' + stats.size + ' bytes) — likely error response');
  }

  const folder = item._contentType === 'local-book' ? 'books' : 'signals';

  console.log('[TTS Audio] Generated ' + filename + ' — ' + (stats.size / 1024).toFixed(0) + 'KB, voice=' + voice + ', lang=' + lang);

  return [{ json: {
    ...item,
    _ttsAudioPath: tempPath,
    _ttsFilename: filename,
    _ttsAudioFolder: folder
  } }];
} catch (err) {
  console.log('[TTS Audio] Error: ' + err.message + ' — continuing without audio');
  return [{ json: { ...item, _ttsAudioPath: null, _ttsFilename: null, _ttsAudioFolder: null } }];
}

// upload MP3 to NextCloud via WebDAV PUT
// require('https') is blocked in n8n sandbox, this.helpers.httpRequest
// JSON-serializes Buffers (broken files), so we spawn('node', ['-e', script])
// AFTER UPLOAD: PROPFIND to get NC file ID, builds /index.php/f/<id> URL

const { spawn } = require('child_process');

const item = $input.first().json;

if (!item._ttsAudioPath) {
  return [{ json: { ...item, _ttsAudioUrl: null } }];
}

try {
  const folder = item._ttsAudioFolder || 'signals';
  const filename = item._ttsFilename;
  const tempPath = item._ttsAudioPath;
  const uploadPath = '/remote.php/webdav/Shared/Shared/Pipeline/Audio/' + folder + '/' + filename;
  const creds = Buffer.from('YOUR_NEXTCLOUD_USER:@8D89JS@u6EQ%8al').toString('base64');

  // Helper: spawn a node process and return stdout
  function runNode(script, args) {
    return new Promise((resolve, reject) => {
      const proc = spawn('node', ['-e', script, ...args]);
      let stdout = '';
      let stderr = '';
      proc.stdout.on('data', d => stdout += d.toString());
      proc.stderr.on('data', d => stderr += d.toString());
      proc.on('close', code => {
        if (code === 0 && stdout) {
          try { resolve(JSON.parse(stdout)); }
          catch(e) { resolve({ raw: stdout }); }
        } else {
          reject(new Error('Process exited ' + code + ': ' + stderr));
        }
      });
      proc.on('error', e => reject(e));
    });
  }

  // Step 1: Upload the MP3 via HTTPS PUT
  const uploadScript = `
    const https = require('https');
    const fs = require('fs');
    const data = fs.readFileSync(process.argv[1]);
    const req = https.request({
      hostname: 'YOUR_NEXTCLOUD_DOMAIN',
      path: process.argv[2],
      method: 'PUT',
      headers: {
        'Content-Type': 'audio/mpeg',
        'Content-Length': data.length,
        'Authorization': 'Basic ' + process.argv[3]
      }
    }, (res) => {
      let body = '';
      res.on('data', c => body += c);
      res.on('end', () => {
        process.stdout.write(JSON.stringify({ statusCode: res.statusCode, body: body, size: data.length }));
      });
    });
    req.on('error', (e) => {
      process.stderr.write(e.message);
      process.exit(1);
    });
    req.write(data);
    req.end();
  `;

  const uploadResult = await runNode(uploadScript, [tempPath, uploadPath, creds]);
  const sizeMB = ((uploadResult.size || 0) / 1024 / 1024).toFixed(1);

  if (uploadResult.statusCode >= 200 && uploadResult.statusCode < 300) {
    console.log('[NC Upload Audio] Uploaded ' + filename + ' to ' + folder + '/ (' + sizeMB + 'MB, HTTP ' + uploadResult.statusCode + ')');
  } else {
    console.log('[NC Upload Audio] Upload returned HTTP ' + uploadResult.statusCode + ': ' + uploadResult.body);
    return [{ json: { ...item, _ttsAudioUrl: null } }];
  }

  // Step 2: PROPFIND to get the file's NextCloud file ID
  // This lets us build an /index.php/f/<id> URL that:
  // - requires NC login (authenticated, private)
  // - opens in the NC web UI with audio player
  // - works for any user who has access to the shared folder
  const propfindScript = `
    const https = require('https');
    const propfindBody = '<?xml version="1.0"?><d:propfind xmlns:d="DAV:" xmlns:oc="http://owncloud.org/ns"><d:prop><oc:fileid/></d:prop></d:propfind>';
    const req = https.request({
      hostname: 'YOUR_NEXTCLOUD_DOMAIN',
      path: process.argv[1],
      method: 'PROPFIND',
      headers: {
        'Content-Type': 'application/xml',
        'Depth': '0',
        'Authorization': 'Basic ' + process.argv[2]
      }
    }, (res) => {
      let body = '';
      res.on('data', c => body += c);
      res.on('end', () => {
        const match = body.match(/<oc:fileid>(\\d+)<\\/oc:fileid>/);
        if (match) {
          process.stdout.write(JSON.stringify({ fileId: match[1], statusCode: res.statusCode }));
        } else {
          process.stdout.write(JSON.stringify({ fileId: null, statusCode: res.statusCode, body: body.substring(0, 200) }));
        }
      });
    });
    req.on('error', (e) => {
      process.stderr.write(e.message);
      process.exit(1);
    });
    req.write(propfindBody);
    req.end();
  `;

  let audioUrl = null;
  try {
    const propResult = await runNode(propfindScript, [uploadPath, creds]);
    if (propResult.fileId) {
      // Authenticated NC URL. opens in web UI with player when logged in
      audioUrl = 'https://YOUR_NEXTCLOUD_DOMAIN/index.php/f/' + propResult.fileId;
      console.log('[NC Upload Audio] File ID: ' + propResult.fileId + ' → ' + audioUrl);
    } else {
      console.log('[NC Upload Audio] PROPFIND did not return file ID: ' + JSON.stringify(propResult));
    }
  } catch(propErr) {
    console.log('[NC Upload Audio] PROPFIND failed: ' + propErr.message + ' — link will be null');
  }

  // NOTE: Do NOT delete temp audio file here. Send Signal Response needs it for attachment
  return [{ json: { ...item, _ttsAudioUrl: audioUrl } }];
} catch (err) {
  console.log('[NC Upload Audio] Error: ' + err.message + ' — continuing without upload');
  return [{ json: { ...item, _ttsAudioUrl: null } }];
}
